import React, { memo, useMemo, useState } from "react";
import { motion } from "framer-motion";
import { Link } from "react-router-dom";
import { Button } from "./src/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>
    {children}
  </section>
);

const formatPublishDate = (date) => {
  if (!date) return "Värske";
  const parsed = new Date(date);
  if (Number.isNaN(parsed.getTime())) return date;
  return parsed.toLocaleDateString("et-EE", { day: "numeric", month: "short", year: "numeric" });
};

const BlogPreviewSection = memo(({ posts = [], primaryBlogLink = "/blog" }) => {
  const categories = useMemo(() => {
    const unique = Array.from(new Set(posts.map((post) => post.category).filter(Boolean)));
    return ["Kõik", ...unique];
  }, [posts]);

  const [activeCategory, setActiveCategory] = useState("Kõik");

  const sortedPosts = useMemo(() => {
    return [...posts].sort((a, b) => {
      const aTime = new Date(a.publishedAt).getTime();
      const bTime = new Date(b.publishedAt).getTime();
      return Number.isFinite(bTime) && Number.isFinite(aTime) ? bTime - aTime : 0;
    });
  }, [posts]);

  const featuredPosts = useMemo(() => {
    const filtered =
      activeCategory === "Kõik"
        ? sortedPosts
        : sortedPosts.filter((post) => post.category === activeCategory);
    return filtered.slice(0, 3);
  }, [activeCategory, sortedPosts]);

  return (
    <Section id="blog" className="py-12">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardHeader className="text-center">
          <CardTitle asChild className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
            <h2>Nõuanded autohoolduseks</h2>
          </CardTitle>
          <p className="mt-3 text-slate-800 dark:text-slate-300">
            Värsked artiklid, lugemissoovitused ja samm-sammulised juhised, et oma autot ennetavalt
            hooldada.
          </p>
          <div className="mt-6 flex flex-wrap justify-center gap-3">
            {categories.map((category) => (
              <button
                key={category}
                type="button"
                onClick={() => setActiveCategory(category)}
                className={`rounded-full border px-4 py-1 text-xs font-semibold transition ${
                  activeCategory === category
                    ? "border-[#0F62FE] bg-[#0F62FE] text-white shadow-md"
                    : "border-slate-300 bg-white text-slate-600 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-300"
                }`}
                aria-pressed={activeCategory === category}
              >
                {category}
              </button>
            ))}
          </div>
        </CardHeader>
        <CardContent>
          {featuredPosts.length === 0 ? (
            <p className="text-center text-sm text-slate-600 dark:text-slate-300">
              Valitud kategooria jaoks artikleid ei leitud. Vaheta kategooriat või vaata kõiki artikleid.
            </p>
          ) : (
            <div className="grid grid-cols-1 gap-6 md:grid-cols-3">
              {featuredPosts.map((post, index) => (
                <motion.div
                  key={post.title}
                  initial={{ opacity: 0, y: 24 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.6, delay: index * 0.15 }}
                  viewport={{ once: true }}
                >
                  <Card className="rounded-3xl border-white/30 bg-white/90 shadow-lg backdrop-blur dark:bg-slate-800/60 dark:border-slate-700 hover:shadow-2xl transition-shadow duration-300">
                    <CardContent className="flex flex-col gap-4 p-6">
                      <div className="overflow-hidden rounded-2xl">
                        <img
                          src={post.image}
                          alt={post.title}
                          loading="lazy"
                          className="h-40 w-full object-cover transition duration-300 group-hover:scale-105"
                        />
                      </div>
                      <div className="flex items-center justify-between text-xs uppercase tracking-wide text-slate-500 dark:text-slate-400">
                        <span className="rounded-full bg-slate-100 px-3 py-1 text-[10px] font-semibold dark:bg-slate-700">
                          {post.category}
                        </span>
                        <span>{post.readTime ?? "3 min"}</span>
                      </div>
                      <div>
                        <h3 className="text-xl font-semibold text-slate-900 dark:text-slate-100">{post.title}</h3>
                        <p className="mt-2 text-sm text-slate-700 dark:text-slate-300">{post.description}</p>
                      </div>
                      <div className="flex items-center justify-between text-[12px] text-slate-500 dark:text-slate-400">
                        <span>{formatPublishDate(post.publishedAt)}</span>
                        <span>Ekspertide valik</span>
                      </div>
                      <Button asChild variant="outline" className="mt-2 rounded-2xl">
                        <Link to={post.to}>Loe artiklit</Link>
                      </Button>
                    </CardContent>
                  </Card>
                </motion.div>
              ))}
            </div>
          )}
          <div className="mt-8 text-center">
            <Button asChild variant="outline" className="rounded-2xl px-6 py-3">
              <Link to={primaryBlogLink}>Vaata kõiki artikleid</Link>
            </Button>
          </div>
        </CardContent>
      </Card>
    </Section>
  );
});

BlogPreviewSection.displayName = "BlogPreviewSection";

export default BlogPreviewSection;
